import "container/list"

type Cell struct {
    x, y int
}

func solve(grid [][]int64, k int64) int64 {
    m := len(grid)
    if m == 0 {
        return 0
    }
    n := len(grid[0])
    var count int64 = 0
    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            if grid[i][j] > 0 {
                queue := list.New()
                queue.PushBack(&Cell{i, j})
                modSum := int64(0)
                modSum = (modSum + grid[i][j]) % k
                grid[i][j] = 0
                for queue.Len() > 0 {
                    cell := queue.Front()
                    queue.Remove(cell)
                    current := cell.Value.(*Cell)
                    x, y := current.x, current.y
                    directions := [][]int{{-1, 0}, {1, 0}, {0, -1}, {0, 1}}
                    for _, dir := range directions {
                        nx := x + dir[0]
                        ny := y + dir[1]
                        if nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0 {
                            queue.PushBack(&Cell{nx, ny})
                            modSum = (modSum + grid[nx][ny]) % k
                            grid[nx][ny] = 0
                        }
                    }
                }
                if modSum == 0 {
                    count++
                }
            }
        }
    }
    return count
}
